// 1. 成员解析：3+ 元素链（f.a.b.c），当前 parser 接受，B0.1 递归下降应保持。
f.red.bold.blur
{deep chain} @ f.red.bold.blur

// 2. 量词类型化（D24 债务）：
//    2a. line 单位——当前 parser 退化为字符串 "0.5line"，B0.1 应类型化为空间量词。
hold(0.5line)
{line unit} @ f.hold(0.5line)

//    2b. ms 单位——当前 parser 静默转秒（500ms → 0.5），单位信息丢失，B0.1 应保留单位。
hold(500ms)
{ms unit} @ f.hold(500ms)

//    2c. self 单位——当前 parser 退化为字符串 "1self"，B0.1 应类型化。
left(1self)
{self unit} @ f.left(1self)

//    2d. deg 单位——当前 parser 退化为字符串 "15deg"，B0.1 应类型化。
rotate(15deg)
{deg unit} @ f.rotate(15deg)

// 3. ease 词形：spec 已废弃单词形态（migration.md:15），改用连接符 ~d~>。
//    3a. ease=out 作为命名参数——当前 parser 当普通 key=val 处理（params.ease="out"），非 ease 语法。
hold(1s, ease=out)
{ease named} @ f.hold(1s, ease=out)

//    3b. 废弃单词形态 ease(d)——当前 parser 当普通命令名处理（若未注册则 unknown-command 诊断）。
ease(1s)
{ease word} @ f.ease(1s)

// 5. 括号组嵌套与多组映射（braceGroupId）。
{A}{B}{C} @ f.red
{group mapping} @ f.wave.hold(1s).red

// 6. hold/ease 词形的 level 后缀（:char / :group / :block）。
f.hold:char(1s).red
f.wave.hold:group(2s)

